const _ = require('lodash');

const CONSOLE = require('./console');

const TYPE = {
    /**
     * @memberof BXUI.Type
     */
     "isPlainObject": _isPlainObject,
    /**
     * @memberof BXUI.Type
     */
     "isNumber": _isNumber,
    /**
     * @memberof BXUI.Type
     */
     "isBoolean": _isBoolean
};


/**
 * 객체 유/무를 반환한다.
 * @returns {boolean} 객체 유/무
 *
 * @private
 *
 */
function _isPlainObject(v = null){

    let ret = false;
    let ptn = '^{.*}$';

    if (_.isString(v) && v.match(ptn)){
        ret = true;
    }
    else{
        ret = _.isPlainObject(v);
    }

    return ret;
}

/**
 * number type 유 / 무를 반환한다.
 * @returns {boolean} number 유/무
 *
 * @private
 *
 */
function _isNumber(v = null){

    let ret = null;

    if (_.isNull(v) || !_.trim(v).length || _.isBoolean(v)){
        ret = false;
    }
    else{
        ret = !isNaN(v);
    }
    return ret;
}

/**
 * boolean type 유 / 무를 반환한다.
 * @returns {boolean} boolean 유/무
 *
 * @private
 *
 */
function _isBoolean(v = null){

    return v === 'true' || v === 'false' || v === true || v === false;
}


module.exports = TYPE;